import React from 'react';
import { Link } from 'react-router-dom';
import { useInView } from '../../hooks/useInView';
import './WhyChooseUs.css';

const WhyChooseUs = () => {
  const [contentRef, contentVisible] = useInView();

  return (
    <section className="why-choose-us">
      <div className="container">
        <div
          ref={contentRef}
          className={`why-choose-content reveal-group ${contentVisible ? 'is-visible' : ''}`}
        >
          <h2 className="section-title reveal-item">Strategic Finance for Agency Leaders</h2>
          <div className="qualities-grid">
            <div className="quality-card reveal-item">
              <div className="quality-icon">��</div>
              <h3>Commercially Established</h3>
              <p>You have recurring revenue, long term clients and a business worth managing properly.</p>
            </div>
            <div className="quality-card reveal-item">
              <div className="quality-icon">��️</div>
              <h3>Operationally Complex</h3>
              <p>Team growth, delivery capacity and client mix require clear financial structure.</p>
            </div>
            <div className="quality-card reveal-item">
              <div className="quality-icon">���</div>
              <h3>Strategically Led</h3>
              <p>Leadership that values forecasting, structured reporting and disciplined decision making.</p>
            </div>
          </div>
          <div className="cta-center reveal-item">
            <Link to="/contact" className="btn-primary btn-large">
              Schedule a Call
            </Link>
          </div>
        </div>
      </div>
    </section>
  );
};

export default WhyChooseUs;
